sql:
SELECT AVG(model_id) AS average_model_id
FROM vehicle_models
WHERE production_start_year > 1970;

SELECT vm.model_name
FROM vehicle_models vm
WHERE vm.model_id NOT IN (SELECT al.vehicle_id FROM access_logs al);

SELECT AVG(v.age) AS average_age
FROM vehicles v
WHERE v.horsepower BETWEEN 150 AND 200;

SELECT vehicles.vehicle_id, manufacturers.manufacturer_name
FROM vehicles
JOIN manufacturers ON vehicles.manufacturer_id = manufacturers.manufacturer_id;

SELECT AVG(horsepower) AS Average_Horsepower
FROM vehicles
WHERE production_year = 2020 AND manufacturer_id = 101;
